/**
 * Split a compound question into individual focused questions.
 * Handles: "and also", "also show", "and show", "? and", comma-separated, etc.
 *
 * Each returned question is prefixed with a reminder to answer only that question,
 * preventing Gemini from trying to combine them into one UNION ALL query.
 */

const SPLIT_PATTERNS = [
// "? and also", "? also", "? and"
/\?\s*(?:and also|and|also|additionally)\s+/i,
// "and also show/get/find/list/display/give"
/\s+and also\s+(?=show|get|find|list|display|give|what|which|how|count|top|total|average|sum)/i,
// "also show/get/find" without "and"
/\s+also\s+(?=show|get|find|list|display|give|what|which|how|count|top|total|average|sum)/i,
// ". Also", ". And"
/\.\s+(?:also|and also)\s+/i,
// semicolon separator
/;\s*/];
export function splitQuestions(input) {
  const text = input.trim();

  // Try each pattern until we get a split
  for (const pattern of SPLIT_PATTERNS) {
    const parts = text.split(pattern).map(p => p.replace(/\?+$/, '').trim()).filter(p => p.length > 4);
    if (parts.length >= 2) {
      // Prefix each part so Gemini writes ONE clean query per question
      return parts.map(p => `Answer only this single question with one SQL query (do not use UNION): ${p}`);
    }
  }

  // Single question — no prefix needed
  return [text.replace(/\?+$/, '').trim()];
}

